import React, { type FunctionComponent, useEffect, useRef, useState } from 'react';

import { type PaymentMethodProps } from '@bigcommerce/checkout/payment-integration-api';
import { LoadingOverlay } from '@bigcommerce/checkout/ui';
import { navigateToOrderConfirmation } from '@bigcommerce/checkout/utility';

// Points at the bigcommerce-worldpay-app backend. Update this whenever the
// tunnel/hosting URL changes.
const WORLDPAY_BACKEND_URL = 'https://coastline-arose-alienate.ngrok-free.dev';

const WorldpayElementComponent: FunctionComponent<PaymentMethodProps> = ({
    checkoutService,
    checkoutState,
    method,
    onUnhandledError,
    paymentForm,
}) => {
    const [iframeUrl, setIframeUrl] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [polling, setPolling] = useState(false);
    const [paymentApproved, setPaymentApproved] = useState(false);
    const pollIntervalRef = useRef<ReturnType<typeof setInterval>>();
    const pollStartRef = useRef<number>(0);

    useEffect(() => {
        void loadIframe();

        return () => {
            if (pollIntervalRef.current) {
                clearInterval(pollIntervalRef.current);
            }
            paymentForm.setSubmit(method, null);
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    async function handleManualSubmit() {
        try {
            const submitResult = await checkoutService.submitOrder({
                payment: {
                    methodId: method.id,
                },
            });
            const order = submitResult.data.getOrder();
            void navigateToOrderConfirmation(order?.orderId);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to place order.');

            if (onUnhandledError && err instanceof Error) {
                onUnhandledError(err);
            }
        }
    }

    async function loadIframe() {
        setLoading(true);
        setError(null);

        try {
            const { data } = checkoutState;
            const cart = data.getCart();
            const checkout = data.getCheckout();
            const config = data.getConfig();
            const billingAddress = data.getBillingAddress();

            if (!cart || !checkout || !config) {
                throw new Error('Unable to read checkout data.');
            }

            const storeHash = config.storeProfile?.storeHash;

            if (!storeHash) {
                throw new Error('Unable to determine store for this checkout.');
            }

            const res = await fetch(`${WORLDPAY_BACKEND_URL}/api/element-pay/setup`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'ngrok-skip-browser-warning': 'true' },
                body: JSON.stringify({
                    storeHash,
                    referenceId: checkout.id,
                    billingAddress: billingAddress
                        ? {
                              address1: billingAddress.address1,
                              city: billingAddress.city,
                              postalCode: billingAddress.postalCode,
                              stateOrProvinceCode: billingAddress.stateOrProvinceCode,
                          }
                        : undefined,
                }),
            });

            const setupData = await res.json();

            if (!res.ok) {
                throw new Error(setupData.error || 'Failed to load payment form.');
            }

            setIframeUrl(setupData.iframeUrl);
            paymentForm.disableSubmit(method, true);

            if (setupData.transactionSetupId) {
                startPolling(storeHash, setupData.transactionSetupId);
            }
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Something went wrong.');

            if (onUnhandledError && err instanceof Error) {
                onUnhandledError(err);
            }
        } finally {
            setLoading(false);
        }
    }

    function startPolling(storeHash: string, transactionSetupId: string) {
        setPolling(true);
        pollStartRef.current = Date.now();

        const POLL_INTERVAL_MS = 3000;
        const TIMEOUT_MS = 3 * 60 * 1000;

        pollIntervalRef.current = setInterval(() => {
            void (async () => {
                if (Date.now() - pollStartRef.current > TIMEOUT_MS) {
                    if (pollIntervalRef.current) {
                        clearInterval(pollIntervalRef.current);
                    }

                    setPolling(false);
                    paymentForm.disableSubmit(method, true);
                    setError('Payment timed out. Please try again.');

                    return;
                }

                try {
                    const res = await fetch(
                        `${WORLDPAY_BACKEND_URL}/api/element-pay/status/${storeHash}/${transactionSetupId}`,
                        { headers: { 'ngrok-skip-browser-warning': 'true' } },
                    );
                    const statusData = await res.json();

                    if (statusData.found) {
                        if (pollIntervalRef.current) {
                            clearInterval(pollIntervalRef.current);
                        }

                        setPolling(false);

                        if (statusData.approved) {
                            paymentForm.disableSubmit(method, false);
                            paymentForm.setSubmit(method, () => void handleManualSubmit());
                            setPaymentApproved(true);
                        } else {
                            paymentForm.disableSubmit(method, true);
                            paymentForm.setSubmit(method, null);
                            setError('Payment was declined. Please try a different card.');
                        }
                    }
                } catch (err) {
                    // eslint-disable-next-line no-console
                    console.error('[Worldpay] Poll error:', err);
                }
            })();
        }, POLL_INTERVAL_MS);
    }

    if (error) {
        return (
            <div className="paymentMethod paymentMethod--hosted">
                <p style={{ color: '#d14343' }}>{error}</p>
                <button onClick={() => void loadIframe()} type="button">
                    Try Again
                </button>
            </div>
        );
    }

    return (
        <LoadingOverlay hideContentWhenLoading isLoading={loading}>
            <div className="paymentMethod paymentMethod--hosted">
                {iframeUrl && (
                    <>
                        <iframe
                            frameBorder="0"
                            height="420"
                            scrolling="no"
                            src={iframeUrl}
                            title="Secure Payment Form"
                            width="100%"
                        />
                        {polling && (
                            <p style={{ fontSize: 12, color: '#5f5f5f', textAlign: 'center' }}>
                                Waiting for payment confirmation...
                            </p>
                        )}
                        {paymentApproved && (
                            <p style={{ fontSize: 12, color: '#2b9c4a', textAlign: 'center' }}>
                                Payment approved. Click Place Order to complete your purchase.
                            </p>
                        )}
                    </>
                )}
            </div>
        </LoadingOverlay>
    );
};

export default WorldpayElementComponent;










