import { type FunctionComponent } from 'react';
import React from 'react';

import {
    type PaymentMethodProps,
    type PaymentMethodResolveId,
    toResolvableComponent,
} from '@bigcommerce/checkout/payment-integration-api';

import { WorldpayElementComponent } from './components';

const WorldpayElementPaymentMethod: FunctionComponent<PaymentMethodProps> = (props) => {
    return <WorldpayElementComponent {...props} />;
};

export default toResolvableComponent<PaymentMethodProps, PaymentMethodResolveId>(
    WorldpayElementPaymentMethod,
    [{ type: 'PAYMENT_TYPE_SDK' }],
);






